preludes.idiv:
def _pg_idiv(a, b):
    q = a // b
    return q + 1 if (q < 0 and q * b != a) else q
def _pg_irem(a, b):
    return a - _pg_idiv(a, b) * b

preludes.fstr:
def _pg_str(x):
    if isinstance(x, bool):
        return "true" if x else "false"
    if isinstance(x, float) and x.is_integer() and abs(x) < 1e16:
        return str(int(x))
    return str(x)
